- (void)downloadVApp:(WBVAppModel *)vapp {
    if ([WBStorageManager.sharedManager hasIPA:vapp.bundleId ofSha1Hash:vapp.versionInfo.ipaHash]) {
        [WBStorageManager.sharedManager saveIPARes:vapp];
        [self installVApp:vapp];
    } else {
        [self saveStatus:WBVappStatusWaitingDownload forVApp:vapp];
        [WBVAppDownloadManager.sharedManager addToDownloadQueue:vapp];
        [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeVappDownloading defaultHandler:nil];
    }
}

- (void)forceRedownloadVApp:(WBVAppModel *)vapp {
    [[WBNetworkManager defaultManager] getLatestVersionWithWithVAppId:vapp.vid installedVersion:vapp.versionInfo.version isPassive:false callback:^(WBVAppDetailHttpModel * _Nullable requestedVapp, NSError * _Nullable error) {
        if (error) {
            [SVProgressHUD showErrorWithStatus:error.localizedDescription];
            return;
        }
        // remove old ipa file
        [vapp removeCacheFileOrDirIfExist:vapp.userInfo.ipaZipPath];
        [vapp removeCacheFileOrDirIfExist:vapp.userInfo.ipaUnzipPath];

        // remove old res file
        [vapp removeCacheFileOrDirIfExist:vapp.userInfo.resZipPath];
        [vapp removeCacheFileOrDirIfExist:vapp.userInfo.resUnzipPath];

        [vapp updateWithVAppDetailModel:requestedVapp];
        [self downloadVApp:vapp];
    }];
}

