- (BOOL)loadUUIDFromKeychain {
    NSError *error = nil;
    _uuid = [SAMKeychain passwordForService:ABBridge_GetAppCodeName() account:WEBOX_ACCOUNT_UUID error:&error];
    if (error && error.code == errSecItemNotFound) {
        // if not found, create one, make sure create is success
        [self createAndSetUUID];
    }
    return _uuid != nil;
}

- (BOOL)loadUUID {
    // first try to load from user defaults
    _uuid = WBSettingManager.sharedManager.UUID;
    if (_uuid != nil) {
        NSLog(@"[AUTH] uuid from userdefaults:%@", _uuid);
        return TRUE;
    }
    // if user defaults's not available (the app might be deleted and reinstalled), try load from keychain
    if ([self loadUUIDFromKeychain]) {
        NSLog(@"[AUTH] uuid from keychain:%@", _uuid);
        // save it to userdefaults so that next time we could load from userdefaults (fast)
        WBSettingManager.sharedManager.UUID = _uuid;
        NSLog(@"[AUTH] uuid saved to userdefaults.");
        return TRUE;
    }
    return FALSE;
}


- (BOOL)createAndSetUUID {
    CFUUIDRef uuidRef = CFUUIDCreate(kCFAllocatorDefault);
    CFStringRef strRef = CFUUIDCreateString(kCFAllocatorDefault , uuidRef);
    NSString *uuid = (__bridge NSString *)strRef;
    CFRelease(strRef);
    CFRelease(uuidRef);
    // save it in keychain
    if ([SAMKeychain setPassword:uuid forService:ABBridge_GetAppCodeName() account:WEBOX_ACCOUNT_UUID]) {
        // save it in userdefaults for fast load
        _uuid = uuid;
        NSLog(@"[AUTH] uuid create new:%@", _uuid);
        return TRUE;
    }
    return FALSE;
}

- (NSString *)getCarrierString {
    NSDictionary *carriersProviders = [[[CTTelephonyNetworkInfo alloc] init] serviceSubscriberCellularProviders];
    __block NSString *value = @"";
    [carriersProviders enumerateKeysAndObjectsUsingBlock:^(NSString *  _Nonnull identifier, CTCarrier *  _Nonnull carrier, BOOL * _Nonnull stop) {
        NSString *v = [NSString stringWithFormat:@"%@/%@", carrier.mobileCountryCode, carrier.mobileNetworkCode];
        if ([value length]) {
            value = [value stringByAppendingFormat:@"|%@", v];
        } else {
            value = v;
        }
    }];
    return value;
}

- (NSString *)getProxyString {
    NSDictionary *dict = CFBridgingRelease(CFNetworkCopySystemProxySettings());
    NSArray *keys = [dict[@"__SCOPED__"] allKeys];
    NSArray *keywords = [NSArray arrayWithObjects:@"tap", @"tun", @"ipsec", @"ppp", nil];
    NSMutableDictionary *result = [NSMutableDictionary dictionary];
    for (NSString *key in keys) {
        for (NSString *keyword in keywords) {
            if ([key rangeOfString:keyword].location != NSNotFound) {
                [result setObject:@(YES) forKey:keyword];
            }
        }
    }
    int httpEnabled = dict[@"HTTPEnable"]!=nil? [dict[@"HTTPEnable"] intValue]:0;
    int httpsEnabled = dict[@"HTTPSEnable"]!=nil? [dict[@"HTTPSEnable"] intValue]:0;
    NSString *ret = [NSString stringWithFormat:@"%d|%d", httpEnabled, httpsEnabled];
    for(NSString *key in result) {
        ret = [ret stringByAppendingFormat:@"|%@", key];
    }
    return ret;
}

// 获取操作系统版本
- (NSString *)getOSVersion {
    if (@available(iOS 14.0, macOS 11.0, *)) {
        if ([[NSProcessInfo processInfo] isiOSAppOnMac]) {
            NSString *realVer = nil;
            char buffer[256];
            size_t size = sizeof(buffer);
            if (sysctlbyname("kern.osproductversion", buffer, &size, NULL, 0) == 0) {
                realVer = [NSString stringWithUTF8String:buffer];
            } else {
                realVer = @"MacUnknown";
            }
            return realVer;
        }
    }
    return [UIDevice currentDevice].systemVersion;  // 默认：iOS 设备
}

// 获取硬件型号
- (NSString *)getDeviceModel {
    if (@available(iOS 14.0, macOS 11.0, *)) {
        if ([[NSProcessInfo processInfo] isiOSAppOnMac]) {
            // Mac Catalyst: 获取 Mac 硬件标识（如 MacBookPro18,3）
            char buffer[256];
            size_t size = sizeof(buffer);
            if (sysctlbyname("hw.model", &buffer, &size, NULL, 0) == 0) {
                return [NSString stringWithUTF8String:buffer];
            }
            return @"MacUnknown";
        }
    }

    // 默认：iOS 设备
    struct utsname systemInfo;
    uname(&systemInfo);
    return [NSString stringWithCString:systemInfo.machine encoding:NSUTF8StringEncoding];
}

// 获取物理内存大小（单位：字节）
+ (uint64_t)getPhysicalMemory {
    int mib[2] = {CTL_HW, HW_MEMSIZE};
    uint64_t mem = 0;
    size_t len = sizeof(mem);

    if (sysctl(mib, 2, &mem, &len, NULL, 0) == 0) {
        return mem;
    }
    return 0;
}

