    82	// Dump data to dummy api server, temporary usage.
    83	- (void)dumpJsonToDummyApiServerWithData:(NSData *)jsonData request:(NSURLRequest *)request {
    84	    id json = [NSJSONSerialization JSONObjectWithData:jsonData options:NSJSONReadingFragmentsAllowed error:nil];
    85	    if (!json) return;
    86	    NSMutableArray<NSString *> *pathComponents = [[request.URL.path pathComponents] mutableCopy];
    87	    [pathComponents removeObjectsInRange:NSMakeRange(0, 3)];
    88	    NSUInteger hash = (NSUInteger)&json;
    89	    NSString *hashStr = [NSString stringWithFormat:@"%zx", hash];
    90	    [pathComponents addObject:[hashStr substringFromIndex:[hashStr length] - 4]];
    91	    NSString *cachesPath = NSSearchPathForDirectoriesInDomains(NSCachesDirectory, NSUserDomainMask, true)[0];
    92	    NSString *fileName = [pathComponents componentsJoinedByString:@"_"];
    93	    fileName = [fileName stringByAppendingPathExtension:@"leaf"];
    94	    NSString *filePath = [cachesPath stringByAppendingPathComponent:fileName];
    95	    [[NSFileManager defaultManager] createFileAtPath:filePath contents:nil attributes:nil];
    96	    NSOutputStream *os = [NSOutputStream outputStreamToFileAtPath:filePath append:false];
    97	    [os open];
    98	    [NSJSONSerialization writeJSONObject:json toStream:os options:NSJSONWritingPrettyPrinted error:nil];
    99	}
