   122	- (void)refreshToken:(WBNetworkBaseCallback)callback {
   123	    uint32_t challenge1 = arc4random();
   124	    uint32_t challenge2 = (challenge1 + 0x86868686) ^ 0xbeafbeaf;
   125	    NSData *clientInfoData = [[WBQuery query] clientInfo].wb_JSONData;
   126	    NSAssert(clientInfoData, @"client info serialize error");
   127	    NSString *clientInfoString = [[NSString alloc] initWithData:clientInfoData encoding:NSUTF8StringEncoding];
   128	    NSString *clientInfoBase64String = [clientInfoString wb_base64EncodedString];
   129	    clientInfoString = [clientInfoString stringByAppendingString:@(challenge1).stringValue];
   130	    unsigned char result[16];
   131	#pragma clang diagnostic push
   132	#pragma clang diagnostic ignored "-Wdeprecated-declarations"
   133	    NSData *sigData = [clientInfoString dataUsingEncoding:NSUTF8StringEncoding];
   134	    CC_MD5(sigData.bytes, (CC_LONG)sigData.length, result);
   135	#pragma clang diagnostic pop
   136	    NSString *hash = [NSString stringWithFormat:@"%02X%02X%02X%02X%02X%02X%02X%02X%02X%02X%02X%02X%02X%02X%02X%02X",result[0], result[1], result[2], result[3], result[4], result[5], result[6], result[7],result[8], result[9], result[10], result[11],result[12], result[13], result[14], result[15]];
   137	
   138	    NSDictionary *params = @{
   139	        @"ca" : clientInfoBase64String,
   140	        @"cb" : [NSNumber numberWithUnsignedInt:challenge1],
   141	        @"cc" : [NSNumber numberWithUnsignedInt:challenge2],
   142	        @"signature" : hash,
   143	    };
   144	    
   145	    [self POST:@"user/token" params:params callback:^(id  _Nullable json, NSError * _Nullable error) {
   146	        if (error) return callback(nil, error);
   147	        NSNumber *response = [json objectForKey:@"cr"];
   148	        if (response) {
   149	            uint32_t iresponse = (uint32_t)[response intValue];
   150	            if (iresponse != ((challenge2 + 0x9E3A092B) ^ 0xAB88CD9E)) {
   151	                if ([json respondsToSelector:@selector(removeObjectForKey:)]) {
   152	                    [json removeObjectForKey:@"cr"];
   153	                }
   154	            }
   155	        }
   156	        callback(json, nil);
   157	    }];
   158	}
