   163	- (NSURLRequest *)createRequestWithURL:(NSString *)URL HTTPMethod:(NSString *)HTTPMethod params:(NSDictionary *)params isJsonContentType:(BOOL)isJsonContentType {
   164	    // Create HTTP request.
   165	    NSMutableURLRequest *request = [[NSMutableURLRequest alloc] init];
   166	    request.HTTPMethod = HTTPMethod;
   167	    // Authorize header field.
   168	    if (WBSettingManager.sharedManager.Token) {
   169	        [request addValue:[NSString stringWithFormat:@"Bearer %@", WBSettingManager.sharedManager.Token] forHTTPHeaderField:@"Authorization"];
   170	    }
   171	    
   172	    // 动态设置 Content-Type
   173	    NSString *contentType = isJsonContentType ? @"application/json" : @"application/x-www-form-urlencoded";
   174	    [request addValue:contentType forHTTPHeaderField:@"Content-Type"];
   175	
   176	    // Config POST.
   177	    URL = [self validateUrlString:URL];
   178	    if ([[HTTPMethod uppercaseString] isEqualToString:@"POST"]) {
   179	        if (isJsonContentType) {
   180	            // JSON
   181	            request.HTTPBody = params.wb_JSONData;
   182	        } else {
   183	            // 表单
   184	            request.HTTPBody = params.wb_URLEncodedData;
   185	        }
   186	    // Config GET.
   187	    } else if ([[HTTPMethod uppercaseString] isEqualToString:@"GET"] || !HTTPMethod.length) {
   188	        if (params.count) {
   189	            URL = [URL stringByAppendingFormat:@"?%@", params.wb_URLEncodedString];
   190	        }
   191	    // Fall on unexpected HTTP methods.
   192	    } else {
   193	        NSAssert(NO, @"unexpected HTTP request method");
   194	    }
   195	    request.URL = [NSURL URLWithString:URL];
   196	    return request;
   197	}
