   199	- (NSString *)validateUrlString:(NSString *)urlStr {
   200	    NSURL *url = [NSURL URLWithString:urlStr];
   201	    if (url.scheme.length && url.host.length && url.path) return urlStr;
   202	    return [[self.baseURL absoluteString] stringByAppendingPathComponent:urlStr];
   203	}
