   205	- (NSURLRequest *)createMultipartRequestWithURL:(NSString *)URL params:(NSDictionary *)params {
   206	    // Create HTTP request.
   207	    NSMutableURLRequest *request = [[NSMutableURLRequest alloc] init];
   208	    request.HTTPMethod = @"POST";
   209	    NSURL *absoluteURL = [self.baseURL URLByAppendingPathComponent:URL];
   210	     request.URL = absoluteURL;
   211	    // Authorize header field.
   212	    if (WBSettingManager.sharedManager.Token) {
   213	        [request addValue:[NSString stringWithFormat:@"Bearer %@", WBSettingManager.sharedManager.Token] forHTTPHeaderField:@"Authorization"];
   214	    }
   215	
   216	    // Set up boundary.
   217	    NSString *boundary = [NSString stringWithFormat:@"Boundary-%@", [[NSUUID UUID] UUIDString]];
   218	    [request addValue:[NSString stringWithFormat:@"multipart/form-data; boundary=%@",boundary] forHTTPHeaderField:@"Content-Type"];
   219	    // Set up data in request body.
   220	    NSMutableData *postData = [[NSMutableData alloc] init];
   221	    
