    if (!self.expireDate) return false;
    return [self.expireDate compare:[NSDate date]] != NSOrderedDescending;
}

#pragma mark - YYKit data mapping

+ (nullable NSArray<NSString *> *)modelPropertyBlacklist {
    return @[
        NSStringFromSelector(@selector(expireDate)),
        NSStringFromSelector(@selector(useDate)),
        NSStringFromSelector(@selector(isExpired)),
        NSStringFromSelector(@selector(selected)),
        @"checking",
    ];
}

+ (NSDictionary *)modelCustomPropertyMapper {
    return @{
        NSStringFromSelector(@selector(promoId)): @"id",
        NSStringFromSelector(@selector(minCharge)): @"min_charge",
        NSStringFromSelector(@selector(expireDate)): @"expired_at",
        NSStringFromSelector(@selector(useDate)): @"used_at",
    };
}

- (BOOL)modelCustomTransformFromDictionary:(NSDictionary *)dict {
    NSDateFormatter *dateFormatter = [NSDateFormatter wb_isoDateFormatter];
    NSString *kExpireDate = [[self class] modelCustomPropertyMapper][NSStringFromSelector(@selector(expireDate))];
    NSString *expireDateStr = dict[kExpireDate];
    if ([expireDateStr isKindOfClass:[NSString class]] && expireDateStr.length) {
        self.expireDate = [dateFormatter dateFromString:expireDateStr];
    }
    NSString *kUseDate = [[self class] modelCustomPropertyMapper][NSStringFromSelector(@selector(useDate))];
    NSString *useDateStr = dict[kUseDate];
    if ([useDateStr isKindOfClass:[NSString class]] && useDateStr.length) {
        self.useDate = [dateFormatter dateFromString:useDateStr];
    }
    return true;
}

- (id)copy {
    WBPromoModel *copiedPromo = [[WBPromoModel alloc] init];
    copiedPromo = [WBPromoModel modelWithJSON:[self modelToJSONObject]];
    copiedPromo.expireDate = self.expireDate;
    copiedPromo.useDate = self.useDate;
    copiedPromo.selected = self.isSelected;
    self.checking = self.isChecking;
    return copiedPromo;
}

@end

